// Test: storm-force winds should instantly trigger black (do not go out)
async function testComputeSeaStatusBlackWind() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 45,      // storm force — instant black trigger
    windGusts: 55,
    waveHeight: 1.0,    // even with calm seas
    precipitation: 0,
    pressure: 1013,
    cloudCover: 50
  });

  assertEquals(result.level, 'black', 'Storm winds should trigger black');
  assertEquals(result.label, 'Do NOT Go Out');
  assertEquals(result.score, 0, 'Black from instant trigger should be score 0');
  assert(result.reasons[0].includes('Storm-force'), 'Should mention storm-force winds');
}
